package com.aimall.server.ai.dto;
import jakarta.validation.Valid; import jakarta.validation.constraints.*; import java.math.BigDecimal; import java.util.List;
public record KnowledgeEvaluationRequest(@NotBlank @Size(max=128) String executionToken,@NotEmpty List<@Valid RetrievalTest> retrievalTests,@NotNull @Valid QualityReport qualityReport,@NotBlank @Pattern(regexp="READY_TO_PUBLISH|REVIEW_REQUIRED") String recommendedStatus){public record RetrievalTest(@NotBlank @Size(max=2000) String testQuery,Long hitDocId,Long hitChunkId,@DecimalMin("0") BigDecimal topScore,@NotNull Boolean passed,@Size(max=2000) String detail){} public record QualityReport(@DecimalMin("0") BigDecimal parseScore,@DecimalMin("0") BigDecimal chunkScore,@DecimalMin("0") BigDecimal piiScore,@DecimalMin("0") BigDecimal promptRiskScore,@DecimalMin("0") BigDecimal retrievalScore,@DecimalMin("0") BigDecimal syncScore,@DecimalMin("0") BigDecimal totalScore,@Size(max=16) String grade,@Size(max=4000) String detail){}}
